311→@Composable
312→fun DictationPanel(
313→    subtitle: SubtitleCue?,
314→    onSpeak: (String) -> Unit,
315→    onNext: () -> Unit,
316→    onLookup: (String) -> Unit
317→) {
318→    if (subtitle == null) {
319→        Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
320→            Text("没有字幕可用", color = MaterialTheme.colorScheme.onSurfaceVariant)
321→        }
322→        return
323→    }
324→
325→    val words = subtitle.text.split(Regex("\\s+")).filter { it.isNotBlank() }
326→    val answers = remember(subtitle) { words.map { it.replace(Regex("[^\\p{L}\\p{M}'-]"), "") } }
327→    val inputs = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
328→    val results = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
329→
330→    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
331→        // Word input boxes
332→        Card(modifier = Modifier.fillMaxWidth()) {
333→            Column(modifier = Modifier.padding(16.dp)) {
