335→                    modifier = Modifier.fillMaxWidth(),
336→                    horizontalArrangement = Arrangement.spacedBy(8.dp),
337→                    verticalAlignment = Alignment.CenterVertically
338→                ) {
339→                    words.forEachIndexed { i, word ->
340→                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
341→                            OutlinedTextField(
342→                                value = inputs[i],
343→                                onValueChange = { inputs[i] = it },
344→                                modifier = Modifier.width((word.length * 14 + 30).coerceAtLeast(60).dp),
345→                                singleLine = true,
346→                                isError = results[i] == "wrong",
347→                                colors = OutlinedTextFieldDefaults.colors(
348→                                    focusedBorderColor = if (results[i] == "correct") Color.Green else MaterialTheme.colorScheme.primary
349→                                )
350→                            )
351→                            if (results[i] == "wrong") {
352→                                Text(answers[i], color = MaterialTheme.colorScheme.error, style = MaterialTheme.typography.labelSmall)
353→                            }
354→                            TextButton(onClick = { onLookup(word.replace(Regex("[^\\p{L}\\p{M}'-]"), "")) }) {
355→                                Text("查词", style = MaterialTheme.typography.labelSmall)
356→                            }
357→                        }
358→                    }
359→                }
360→            }
361→        }
362→
363→        Spacer(Modifier.height(12.dp))
364→
365→        // Control buttons
366→        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
367→            Button(onClick = { onSpeak(subtitle.text) }) {
368→                Icon(Icons.Default.VolumeUp, null, Modifier.size(16.dp))
369→                Spacer(Modifier.width(4.dp))
370→                Text("朗读")
371→            }
372→            Button(onClick = {
373→                answers.forEachIndexed { i, answer ->
374→                    results[i] = if (inputs[i].trim().equals(answer, ignoreCase = true)) "correct" else "wrong"
375→                }
376→            }) {
377→                Icon(Icons.Default.Check, null, Modifier.size(16.dp))
378→                Spacer(Modifier.width(4.dp))
379→                Text("检查")
380→            }
381→            Button(onClick = {
382→                inputs.indices.forEach { inputs[it] = "" }
383→                results.indices.forEach { results[it] = "" }
384→                onNext()
385→            }) {
386→                Icon(Icons.Default.ArrowForward, null, Modifier.size(16.dp))
387→                Spacer(Modifier.width(4.dp))
388→                Text("下一句")
389→            }
390→        }
391→    }
392→}
