 51→    private val aiConfigStore: AIConfigStore,
 52→    private val aiService: AIService,
 53→    private val dictionaryService: DictionaryService,
 54→    private val whisperService: WhisperService
 55→) : AndroidViewModel(application) {
 56→
 57→    private val _uiState = MutableStateFlow(PlayerUiState())
 58→    val uiState: StateFlow<PlayerUiState> = _uiState.asStateFlow()
 59→
 60→    private var tts: TextToSpeech? = null
 61→    private val json = Json { ignoreUnknownKeys = true }
 62→
 63→    init {
 64→        tts = TextToSpeech(application) { status ->
 65→            if (status == TextToSpeech.SUCCESS) {
 66→                tts?.language = Locale.US
 67→            }
 68→        }
