 71→    fun loadSubtitles(videoPath: String, subtitlePath: String?) {
 72→        viewModelScope.launch(Dispatchers.IO) {
 73→            // Try loading VTT subtitle
 74→            val vttPath = subtitlePath ?: findExistingSubtitle(videoPath)
 75→            if (vttPath != null) {
 76→                val file = File(vttPath)
 77→                if (file.exists()) {
 78→                    val content = file.readText()
 79→                    val subs = VttParser.parse(content)
 80→                    if (subs.isNotEmpty()) {
 81→                        _uiState.update { it.copy(
 82→                            subtitles = subs,
 83→                            statusText = "已加载 ${subs.size} 条字幕"
 84→                        )}
 85→                        // Load word timestamps if available
 86→                        loadWordTimestamps(vttPath)
 87→                        return@launch
 88→                    }
 89→                }
 90→            }
 91→            _uiState.update { it.copy(statusText = "无字幕文件，请在 AI 设置中配置 Groq Whisper 后重新转录") }
 92→        }
 93→    }
 94→
 95→    private fun findExistingSubtitle(videoPath: String): String? {
 96→        val base = videoPath.substringBeforeLast(".")
 97→        for (ext in listOf(".vtt", ".srt")) {
 98→            val f = File(base + ext)
 99→            if (f.exists()) return f.absolutePath
100→        }
101→        // Check with language suffix
102→        val dir = File(videoPath).parentFile ?: return null
103→        val name = File(videoPath).nameWithoutExtension
104→        dir.listFiles()?.forEach { f ->
105→            if (f.name.startsWith(name) && f.extension == "vtt") return f.absolutePath
106→        }
107→        return null
108→    }
109→
110→    private fun loadWordTimestamps(vttPath: String) {
111→        val wtsPath = vttPath.replace(Regex("\\.vtt$"), ".wordts.json")
112→        val wtsFile = File(wtsPath)
113→        if (wtsFile.exists()) {
114→            try {
115→                val timings: List<WordTimestamp> = json.decodeFromString(wtsFile.readText())
116→                _uiState.update { it.copy(wordTimings = timings) }
117→            } catch (_: Exception) {}
118→        }
119→    }
120→
121→    /** Called every 30ms from the player to sync subtitles */
122→    fun updatePosition(positionMs: Long) {
123→        _uiState.update { it.copy(currentPositionMs = positionMs) }
124→        val subs = _uiState.value.subtitles
125→        if (subs.isEmpty()) return
126→
127→        // Binary search for current cue (ported from renderer.js)
128→        var lo = 0; var hi = subs.size - 1; var idx = -1
129→        while (lo <= hi) {
130→            val mid = (lo + hi) ushr 1
131→            when {
132→                positionMs < subs[mid].startMs -> hi = mid - 1
133→                positionMs > subs[mid].endMs -> lo = mid + 1
134→                else -> { idx = mid; break }
135→            }
136→        }
137→        // Gap handling: find next cue within 0.5s
138→        if (idx < 0) {
139→            for (i in subs.indices) {
140→                if (subs[i].startMs > positionMs) {
141→                    idx = if (subs[i].startMs - positionMs < 500) i else if (i > 0) i - 1 else 0
142→                    break
143→                }
144→            }
145→            if (idx < 0) idx = subs.size - 1
146→        }
147→
148→        if (idx != _uiState.value.currentCueIndex) {
149→            _uiState.update { it.copy(
150→                currentCueIndex = idx,
151→                currentSentence = subs[idx].text,
152→                showWordCard = false,
153→                aiAnalysisResult = null
154→            )}
155→        }
156→    }
157→
158→    /** Retranscribe - ported from renderer.js retranscribeBtn click handler.
159→     *  Deletes existing subtitle files and triggers Groq Whisper transcription. */
160→    fun retranscribe(videoPath: String) {
161→        viewModelScope.launch(Dispatchers.IO) {
162→            // Delete existing subtitle files
163→            val base = videoPath.substringBeforeLast(".")
164→            listOf(".vtt", ".wordts.json").forEach { ext ->
165→                val f = File(base + ext)
166→                if (f.exists()) f.delete()
167→            }
168→            // Also check language-suffixed vtt
169→            File(videoPath).parentFile?.listFiles()?.forEach { f ->
170→                val name = File(videoPath).nameWithoutExtension
171→                if (f.name.startsWith(name) && (f.extension == "vtt" || f.name.endsWith(".wordts.json"))) {
172→                    f.delete()
173→                }
174→            }
175→
176→            _uiState.update { it.copy(
177→                subtitles = emptyList(),
178→                wordTimings = emptyList(),
179→                currentCueIndex = -1,
180→                isTranscribing = true,
181→                statusText = "正在重新转录..."
182→            )}
183→
184→            // Transcribe via Groq Whisper
185→            val config = aiConfigStore.config.first()
186→            if (!config.groqWhisperEnabled || config.apiKey.isBlank()) {
187→                _uiState.update { it.copy(isTranscribing = false, statusText = "请先在 AI 设置中配置 Groq Whisper") }
188→                return@launch
189→            }
190→
191→            val vttPath = base + ".vtt"
192→            val wtsPath = base + ".wordts.json"
193→            val vttBuilder = StringBuilder("WEBVTT\n\n")
194→            val allWordTimings = mutableListOf<WordTimestamp>()
195→
196→            // Extract audio segments (10 min each) using ffmpeg from youtubedl-android
197→            // For simplicity, try transcribing the video file directly
198→            val videoFile = File(videoPath)
199→            val result = whisperService.transcribeGroq(videoFile, config)
200→
201→            if (result != null && result.success && result.text.isNotBlank()) {
202→                // Build VTT from word timestamps
203→                if (result.words.isNotEmpty()) {
204→                    var curWords = mutableListOf<WordTimestamp>()
205→                    for (wt in result.words) {
206→                        curWords.add(wt)
207→                        if (wt.w.trim().matches(Regex(".*[.!?。！？]$")) && curWords.isNotEmpty()) {
208→                            val sentText = curWords.joinToString(" ") { it.w }
209→                            val sStart = curWords.first().s
210→                            val sEnd = curWords.last().e
211→                            vttBuilder.append("${VttParser.formatVtt(sStart)} --> ${VttParser.formatVtt(sEnd)}\n$sentText\n\n")
212→                            allWordTimings.addAll(curWords)
213→                            curWords = mutableListOf()
214→                        }
215→                    }
216→                    if (curWords.isNotEmpty()) {
217→                        val sentText = curWords.joinToString(" ") { it.w }
218→                        val sStart = curWords.first().s
219→                        val sEnd = curWords.last().e
220→                        vttBuilder.append("${VttParser.formatVtt(sStart)} --> ${VttParser.formatVtt(sEnd)}\n$sentText\n\n")
221→                        allWordTimings.addAll(curWords)
222→                    }
223→                }
224→
225→                // Save files
226→                File(vttPath).writeText(vttBuilder.toString())
227→                if (allWordTimings.isNotEmpty()) {
228→                    File(wtsPath).writeText(json.encodeToString(kotlinx.serialization.builtins.ListSerializer(WordTimestamp.serializer()), allWordTimings))
229→                }
230→
231→                // Reload
232→                val subs = VttParser.parse(vttBuilder.toString())
233→                _uiState.update { it.copy(
234→                    subtitles = subs,
235→                    wordTimings = allWordTimings,
236→                    isTranscribing = false,
237→                    statusText = "重新转录完成，共 ${subs.size} 条字幕"
238→                )}
239→            } else {
240→                _uiState.update { it.copy(isTranscribing = false, statusText = "转录失败") }
241→            }
242→        }
243→    }
