252→        tts?.language = Locale.forLanguageTag(locale)
253→    }
254→
255→    /** Look up a word - ported from renderer.js showWordInline() */
256→    fun lookupWord(word: String) {
257→        _uiState.update { it.copy(showWordCard = true, wordCardData = WordCardData(word = word, translation = "查询中...")) }
258→        speak(word)
259→
260→        viewModelScope.launch(Dispatchers.IO) {
261→            val lang = _uiState.value.currentLang
262→            val context = _uiState.value.currentSentence
263→
264→            // Parallel lookups
265→            val aiConfig = aiConfigStore.config.first()
266→            val aiTransPromise = launch { aiTranslateWord(word, context, lang, aiConfig) }
267→
268→            val cardData = when (lang) {
269→                "en" -> {
270→                    val online = dictionaryService.lookupEnglish(word)
271→                    val translation = dictionaryService.translate(word, "en")
272→                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
273→                    WordCardData(
274→                        word = word,
275→                        phonetic = online?.phonetic ?: "",
276→                        translation = aiTrans ?: translation ?: online?.translation ?: "未找到释义",
277→                        definitions = online?.definitions ?: emptyList(),
278→                        examples = online?.examples ?: emptyList()
279→                    )
280→                }
281→                "ja" -> {
282→                    val online = dictionaryService.lookupJapanese(word)
283→                    val translation = dictionaryService.translate(word, "ja")
284→                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
285→                    WordCardData(
286→                        word = word,
287→                        phonetic = online?.phonetic ?: "",
288→                        translation = aiTrans ?: translation ?: "未找到释义",
289→                        definitions = online?.definitions ?: emptyList()
290→                    )
291→                }
292→                else -> {
293→                    val translation = dictionaryService.translate(word, lang)
294→                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
295→                    WordCardData(
296→                        word = word,
297→                        translation = aiTrans ?: translation ?: "未找到释义"
298→                    )
299→                }
300→            }
301→            _uiState.update { it.copy(wordCardData = cardData) }
302→        }
303→    }
304→
305→    private suspend fun aiTranslateWord(word: String, context: String, lang: String, config: AIConfig): String? {
306→        val langName = LANGUAGES.find { it.code == lang }?.name ?: "英语"
307→        val prompt = "将${langName}「${word}」翻译为中文。${if (context.isNotBlank()) "语境:\"$context\"。" else ""}只回复中文释义，多义项用/分隔，不要音译。"
308→        return aiService.chat(config, prompt)
309→    }
310→
311→    fun hideWordCard() { _uiState.update { it.copy(showWordCard = false) } }
312→
313→    /** AI analyze sentence - ported from main.js ai-analyze-sentence */
314→    fun analyzeSentence() {
315→        val sentence = _uiState.value.currentSentence
316→        if (sentence.isBlank()) return
317→        _uiState.update { it.copy(isAnalyzing = true, aiAnalysisResult = "🤖 AI分析中...") }
318→
319→        viewModelScope.launch(Dispatchers.IO) {
320→            val lang = _uiState.value.currentLang
321→            val langName = LANGUAGES.find { it.code == lang }?.name ?: lang
322→            val config = aiConfigStore.config.first()
323→            val prompt = """分析${langName}句子："$sentence"
324→【翻译】中文翻译
325→【语法】1-2个关键语法点
326→【重点词汇】2-3个重要词汇及释义"""
327→            val result = aiService.chat(config, prompt)
328→            _uiState.update { it.copy(
329→                isAnalyzing = false,
330→                aiAnalysisResult = result ?: "AI未配置或请求失败，请在设置中配置API Key"
331→            )}
332→        }
333→    }
334→
335→    /** Favorite operations */
336→    suspend fun isFavorite(word: String): Boolean {
337→        return favoriteRepository.isFavorite(word, _uiState.value.currentLang)
338→    }
339→
340→    fun toggleFavorite(word: String, phonetic: String = "", translation: String = "") {
341→        viewModelScope.launch {
342→            val lang = _uiState.value.currentLang
343→            if (favoriteRepository.isFavorite(word, lang)) {
344→                favoriteRepository.remove(word, lang)
345→            } else {
346→                favoriteRepository.add(word, lang, phonetic, translation, _uiState.value.currentSentence)
347→            }
348→        }
349→    }
350→
351→    /** TTS */
352→    fun speak(text: String) {
353→        tts?.speak(text, TextToSpeech.QUEUE_FLUSH, null, "word_tts")
354→    }
355→
356→    /** Dictation */
357→    fun nextDictation() {
358→        val nextIdx = (_uiState.value.dictationIndex + 1).coerceAtMost(_uiState.value.subtitles.size - 1)
359→        _uiState.update { it.copy(dictationIndex = nextIdx) }
360→    }
361→
362→    /** Get aligned word timings for current cue */
363→    fun getAlignedTimings(words: List<String>): List<WordTimestamp?> {
364→        val state = _uiState.value
365→        val cueIdx = state.currentCueIndex
366→        if (cueIdx < 0 || cueIdx >= state.subtitles.size || state.wordTimings.isEmpty()) {
367→            return List(words.size) { null }
368→        }
369→        val cue = state.subtitles[cueIdx]
370→        return WordAligner.alignWords(words, state.wordTimings, cue.startMs / 1000.0, cue.endMs / 1000.0)
371→    }
372→
373→    override fun onCleared() {
374→        tts?.shutdown()
375→        super.onCleared()
376→    }
377→}
